// ─── Context / provider ───────────────────────────────────────────────────────

interface EditorContextValue {
  state: EditorState;
  dispatch: React.Dispatch<EditorAction>;
  saveCurrentProject: () => void;
  openProject: (id: string) => void;
  closeProject: () => void;
  deleteProjectById: (id: string) => void;
  selectedRoom: EditorRoomDefinition | null;
  canUndo: boolean;
  canRedo: boolean;
}

const EditorContext = createContext<EditorContextValue | null>(null);

export function EditorProvider({
  children,
  storageProvider,
}: {
  children: ReactNode;
  storageProvider?: StorageProvider;
}) {
  if (storageProvider) {
    setStorageProvider(storageProvider);
  }

  const [state, dispatch] = useReducer(editorReducer, {
    ...initialState,
    projects: loadProjectMetas(),
  });

  const saveCurrentProject = useCallback(() => {
    if (!state.currentProject) return;
    saveProject(state.currentProject);
    dispatch({ type: "MARK_SAVED" });
  }, [state.currentProject]);

  const openProject = useCallback(
    (id: string) => {
      const project = loadProject(id);
      if (project) dispatch({ type: "OPEN_PROJECT", project });
    },
    []
  );

  const closeProject = useCallback(() => {
    dispatch({ type: "CLOSE_PROJECT" });
  }, []);

  const deleteProjectById = useCallback((id: string) => {
    deleteProject(id);
    dispatch({ type: "DELETE_PROJECT", id });
  }, []);

  const selectedRoom =
    state.currentProject?.rooms.find(
      (r) => r.id === state.selectedRoomId
    ) ?? null;

  const canUndo = state.past.length > 0;
  const canRedo = state.future.length > 0;

  return (
    <EditorContext.Provider
      value={{
        state,
        dispatch,
        saveCurrentProject,
        openProject,
        closeProject,
        deleteProjectById,
        selectedRoom,
        canUndo,
        canRedo,
      }}
    >
      {children}
    </EditorContext.Provider>
  );
}

export function useEditor() {
  const ctx = useContext(EditorContext);
  if (!ctx) throw new Error("useEditor must be used inside EditorProvider");
  return ctx;
}
