    grad.addColorStop(0.5, hexToRgba(color, alpha * 0.4));
    grad.addColorStop(1,   "transparent");
    ctx.fillStyle = grad;
    ctx.fillRect(cx - radius, cy - radius, radius * 2, radius * 2);
