    this.ctx.fillStyle = actor.definition.isPlayer ? "#4a9eff" : "#ff9a4a";

    const px = actor.x - w / 2;
    const py = actor.y - h;

    this.ctx.fillRect(px + 8, py, w - 16, h - 12);

    const headSize = 16;
    this.ctx.beginPath();
