      "left:50%",
      "transform:translateX(-50%)",
      "max-width:80%",
      "background:rgba(0,0,0,0.85)",
      "color:#ffffcc",
      "font-family:monospace",
      "font-size:13px",
      "padding:8px 18px",
      "border-radius:6px",
      "text-align:center",
      "pointer-events:auto",
      "z-index:8",
      "display:none",
